sql:
SELECT weight_type, AVG(weight_value) AS average_weight
FROM weights
GROUP BY weight_type;

SELECT respondent_id, weight_value
FROM weights
WHERE weight_type = 'final weight' AND date_weighted = '2023-01-15';

external_knowledge:
- 'of age' refers to being 18 years or older; 
- 'confidently answered' refers to a response confidence level above 0.7; 
- 'registered for over a year' refers to a registration period of 365 days or more.
